```javascript
'use strict';

/**
 * Parse a simple config format into an object.
 *  - `#` starts a comment (whole-line or inline), unless inside quotes.
 *  - `key = value` lines; key and value are trimmed.
 *  - Quoted values ("..." / '...') are kept verbatim as strings (no coercion).
 *  - Unquoted values coerce: true/false -> boolean, /^-?\d+$/ -> integer.
 *  - Blank and comment-only lines are ignored.
 */
function parseConfig(text) {
  const result = {};

  for (const rawLine of String(text).split(/\r?\n/)) {
    const line = stripComment(rawLine).trim();
    if (line === '') continue;                 // blank / comment-only -> ignore

    const eq = line.indexOf('=');
    if (eq === -1) continue;                    // no separator -> skip

    const key = line.slice(0, eq).trim();
    if (key === '') continue;                   // empty key -> skip

    result[key] = coerce(line.slice(eq + 1).trim());
  }

  return result;
}

// Drop an unquoted `#` and the rest of the line; quotes protect `#`.
function stripComment(line) {
  let quote = null;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (quote) {
      if (ch === quote) quote = null;
    } else if (ch === '"' || ch === "'") {
      quote = ch;
    } else if (ch === '#') {
      return line.slice(0, i);
    }
  }
  return line;
}

function coerce(value) {
  if (value.length >= 2) {                      // quoted -> strip, no coercion
    const f = value[0], l = value[value.length - 1];
    if ((f === '"' || f === "'") && f === l) return value.slice(1, -1);
  }
  if (value === 'true') return true;
  if (value === 'false') return false;
  if (/^-?\d+$/.test(value)) return parseInt(value, 10);
  return value;
}

module.exports = parseConfig;
```

